use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct ReverseDecoder;impl Crack for Decoder<ReverseDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let decoded: String = text.chars().rev().collect();        if check_string_success(&decoded, text) {            let check_result = checker.check_text(&decoded);            if check_result.is_identified {                result.success = true;                result.unencrypted_text = Some(vec![decoded]);                result.checker_name = check_result.checker_name;            }        }        result    }    fn get_name(&self) -> &'static str { "Reverse" }    fn get_popularity(&self) -> f32 { 0.4 }    fn get_tags(&self) -> &'static [&'static str] { &["reverse", "decoder", "manipulation"] }    fn get_description(&self) -> &'static str { "Reverse decoder that reverses the order of characters in a string." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Reverse_string" }}impl Decoder<ReverseDecoder> {    pub fn new() -> Self {        Decoder {            name: "Reverse",            description: "Reverse decoder that reverses the order of characters in a string.",            link: "https://en.wikipedia.org/wiki/Reverse_string",            tags: vec!["reverse", "decoder", "manipulation"],            popularity: 0.4,            phantom: PhantomData,        }    }}



